import React, { useEffect, useState } from "react";
import { Container, Row, Col, Card, ListGroup, Badge, Spinner, Alert, Button, ProgressBar } from "react-bootstrap";
import { Link } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import api from "../services/api";

function Dashboard() {
  const { user } = useAuth();
  const [stats, setStats] = useState({
    medications: 0,
    appointments: 0,
    upcomingAppointments: 0,
    forumPosts: 0,
    medicalHistoryEntries: 0,
  });
  const [recentMedications, setRecentMedications] = useState([]);
  const [upcomingAppointments, setUpcomingAppointments] = useState([]);
  const [todayAppointments, setTodayAppointments] = useState([]);
  const [recentForumPosts, setRecentForumPosts] = useState([]);
  const [latestMedicalHistory, setLatestMedicalHistory] = useState(null);
  const [loading, setLoading] = useState(true);
  const [greeting, setGreeting] = useState("");

  useEffect(() => {
    setGreeting(getGreeting());
    fetchDashboardData();
  }, []);

  const getGreeting = () => {
    const hour = new Date().getHours();
    return hour < 12 ? "Good morning" : hour < 18 ? "Good afternoon" : "Good evening";
  };

  const fetchDashboardData = async () => {
    try {
      const [medsRes, aptsRes, forumRes, historyRes] = await Promise.all([
        api.get("/api/medications"),
        api.get("/api/appointments"),
        api.get("/api/forum/threads"),
        api.get("/api/profile/medical-history"),
      ]);

      const medications = medsRes.data;
      const appointments = aptsRes.data;
      const forumPosts = forumRes.data;
      const medicalHistory = historyRes.data;

      const now = new Date();
      const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
      const tomorrow = new Date(today);
      tomorrow.setDate(tomorrow.getDate() + 1);

      const upcoming = appointments
        .filter((apt) => new Date(`${apt.appointment_date}T${apt.appointment_time}`) > now)
        .sort((a, b) => new Date(`${a.appointment_date}T${a.appointment_time}`) - new Date(`${b.appointment_date}T${b.appointment_time}`));

      const todayApts = upcoming.filter(
        (apt) => {
          const aptDate = new Date(apt.appointment_date);
          return aptDate >= today && aptDate < tomorrow;
        }
      );

      setStats({
        medications: medications.length,
        appointments: appointments.length,
        upcomingAppointments: upcoming.length,
        forumPosts: forumPosts.length,
        medicalHistoryEntries: medicalHistory.length,
      });

      setRecentMedications(medications.slice(0, 5));
      setUpcomingAppointments(upcoming.slice(0, 4));
      setTodayAppointments(todayApts);
      setRecentForumPosts(forumPosts.slice(0, 3));
      setLatestMedicalHistory(medicalHistory[0] || null);
    } catch (err) {
      console.error("Error fetching dashboard data:", err);
    } finally {
      setLoading(false);
    }
  };

  const formatDateTime = (date, time) => {
    const aptDate = new Date(`${date}T${time}`);
    const now = new Date();
    const diffMs = aptDate - now;
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffHours < 1) return `In ${diffMins} minutes`;
    if (diffHours < 24) return `Today at ${time}`;
    if (diffDays === 1) return `Tomorrow at ${time}`;
    if (diffDays < 7) return `In ${diffDays} days`;
    return aptDate.toLocaleDateString();
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    const now = new Date();
    const diffMs = now - date;
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 1) return "Just now";
    if (diffMins < 60) return `${diffMins}m ago`;
    if (diffHours < 24) return `${diffHours}h ago`;
    if (diffDays < 7) return `${diffDays}d ago`;
    return date.toLocaleDateString();
  };

  const getHealthScore = () => {
    let score = 0;
    if (stats.medications > 0) score += 25;
    if (stats.upcomingAppointments > 0) score += 25;
    if (stats.medicalHistoryEntries > 0) score += 25;
    if (stats.forumPosts > 0) score += 25;
    return score;
  };

  if (loading) return (
    <Container className="mt-4 text-center">
      <Spinner animation="border" variant="primary" />
      <p className="mt-2">Loading dashboard...</p>
    </Container>
  );

  const healthScore = getHealthScore();

  // Reusable Badge for Appointments
  const getAppointmentBadge = (apt) => {
    const label = formatDateTime(apt.appointment_date, apt.appointment_time).includes("Today") ? "Today" : "Upcoming";
    const variant = label === "Today" ? "danger" : "warning";
    return <Badge bg={variant} text={label === "Today" ? "white" : "dark"} className="ms-2">{label}</Badge>;
  };

  return (
    <Container className="mt-4 mb-5">
      {/* Header */}
      <div className="mb-4">
        <h2>{greeting}, {user?.name || "User"}! 👋</h2>
        <p className="text-muted">
          Here's your health overview for {new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}
        </p>
      </div>

      {/* Today's Appointments */}
      {todayAppointments.length > 0 && (
        <Alert variant="warning" className="mb-4 shadow-sm">
          <div className="d-flex align-items-center">
            <i className="bi bi-bell-fill me-3" style={{ fontSize: "2rem" }}></i>
            <div className="flex-grow-1">
              <Alert.Heading className="h6 mb-1">
                You have {todayAppointments.length} appointment{todayAppointments.length > 1 ? "s" : ""} today!
              </Alert.Heading>
              {todayAppointments.map((apt) => (
                <div key={apt.id} className="small">
                  <strong>{apt.title}</strong> at {apt.appointment_time}
                </div>
              ))}
            </div>
            <Link to="/appointments" className="btn btn-warning btn-sm">View Details</Link>
          </div>
        </Alert>
      )}

      {/* Health Score */}
      <Row className="mb-4">
        <Col>
          <Card className="shadow-sm border-0 bg-gradient" style={{ background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)' }}>
            <Card.Body className="text-white">
              <Row className="align-items-center">
                <Col md={8}>
                  <h5 className="mb-2"><i className="bi bi-heart-pulse-fill me-2"></i>Health Profile Completion</h5>
                  <ProgressBar now={healthScore} label={`${healthScore}%`} className="mb-2" style={{ height: '25px', backgroundColor: 'rgba(255,255,255,0.3)' }} />
                  <p className="mb-0 small">
                    {healthScore === 100 ? "🎉 Excellent! Your profile is complete." : "Complete your profile to get the most out of MindCare."}
                  </p>
                </Col>
                <Col md={4} className="text-center">
                  <div style={{ fontSize: '3rem' }}>
                    {healthScore === 100 ? '🏆' : healthScore >= 75 ? '⭐' : healthScore >= 50 ? '📊' : '📝'}
                  </div>
                </Col>
              </Row>
            </Card.Body>
          </Card>
        </Col>
      </Row>

      {/* Quick Stats, Medications, Appointments, Medical History, Forum, Quick Actions, Crisis Banner */}
      {/* Keep your original JSX blocks here, only replace Appointment badge with getAppointmentBadge(apt) */}

      <style>{`
        .hover-lift {
          transition: transform 0.2s ease, box-shadow 0.2s ease;
        }
        .hover-lift:hover {
          transform: translateY(-5px);
          box-shadow: 0 0.5rem 1rem rgba(0, 0, 0, 0.15) !important;
        }
      `}</style>
    </Container>
  );
}

export default Dashboard;
